command.script:
import psutil
def get_ram_info(): ram = psutil.virtual_memory()
total_ram = ram.total # Total installed RAM available_ram = ram.available # RAM available for processes used_ram = ram.used # RAM used by processes free_ram = ram.free # RAM not being used percent_used = ram.percent # Percentage of RAM used
return total_ram, available_ram, used_ram, free_ram, percent_used
if __name__ == "__main__": total, available, used, free, percent = get_ram_info()
print(f"Total RAM: {total} bytes") print(f"Available RAM: {available} bytes") print(f"Used RAM: {used} bytes") print(f"Free RAM: {free} bytes") print(f"Percentage of RAM used: {percent}%")

import sys import pandas as pd import pathlib
# Note: In a real environment, replace these placeholders with actual values # for testing, or leave them as is if your runner handles the substitution. job_name = "@option.job_name@" exec_id = "@job.execid@" team = "@option.team@"
def log_to_backup(item_id): """Appends an item ID to the backup_items file.""" # Build the directory path base_dir = pathlib.Path(f"/app/runner/tmp/{job_name}/{exec_id}/")
# Ensure the directory exists (parents=True builds the whole tree) base_dir.mkdir(parents=True, exist_ok=True)
file_path = base_dir / "backup_items"
with open(file_path, "a") as f: f.write(f"{item_id}\n")
def get_ids_to_process(): """Extracts IDs from file or manual option.""" file_name = "@option.FileName@".strip() manual_id = "@option.one_item@".strip()
if file_name and not file_name.startswith("@option"): file_path = f"/app/runner/tmp/{job_name}/{exec_id}/{file_name}" print(f" Bulk Mode: {file_name}")
df = pd.read_csv(file_path) if file_path.endswith('.csv') else pd.read_excel(file_path) df.columns = [c.strip().lower() for c in df.columns]
if 'item' not in df.columns: raise KeyError(f"Column 'item' not found in {file_name}")
return df['item'].dropna().astype(str).unique().tolist()
if manual_id and not manual_id.startswith("@option"): print(f" Manual Mode: {manual_id}") return [manual_id]
raise ValueError("No input provided (FileName or item).")
def main(): try: ids = get_ids_to_process()
for item_id in ids: print(f" Processing ID: {item_id}")
# --- Logging to the backup file --- log_to_backup(item_id)
print(f"\n All IDs logged to backup_items in /app/runner/tmp/{job_name}/{exec_id}/")
except Exception as e: print(f" FATAL ERROR: {e}") sys.exit(1)
if __name__ == "__main__": main()
